INSERT INTO public.photos VALUES (25803, 'Cine Goya 2008', 'Imagen del "antiguo" cine Goya, que fuera levantado en 1932 con diseâ”œâ–’o del arquitecto Ignacio Mendizâ”œÃ­bal, y que habâ”œÂ¡a llegado al siglo XXI como uno de los escasos testimonios del estilo "Art Dâ”œÂ®co" que supervivâ”œÂ¡an en esta entraâ”œâ–’able ciudad. En el aâ”œâ–’o 2005 fue cerrado, y en el momento de la imagen, en el aâ”œâ–’o de la esplendorosa Expo 2008, el edificio fue vaciado para, conservando su fachada, levantar en su interior necesarias viviendas y espacios comerciales varios. Fuente visual: "La ciudad de Zaragoza de 1908 a 2008", XIII Coloquio de arte aragonâ”œÂ®s, IFC, 2008', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.65106800, -0.88053800, '0101000020E6100000F4531C075E2DECBF6FBC3B3256D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19944327166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19944327166.webp', 'https://www.flickr.com/photos/zaragozaantigua/19944327166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25898, 'Coso Medio c.1973', 'Trolebâ”œâ•‘s y motocarro en la confluencia del Coso con la calle Josefa Amar y Borbâ”œâ”‚n. Fuente visual: foto Daniel Pâ”œÂ®rez, en www.facebook.com/photo.php?fbid=10204174831144596&set...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65177000, -0.87974900, '0101000020E6100000DD09F65FE726ECBFC84109336DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15496982342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15496982342.webp', 'https://www.flickr.com/photos/zaragozaantigua/15496982342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25913, 'Plaza de la Constituciâ”œâ”‚n c.1896', 'Desde la altura del antiguo nâ”¬â•‘ 4 de la plaza de la Constituciâ”œâ”‚n, interesante imagen de la fachada del Coso recayente a esta plaza, en el tramo entre la embocadura a la calle de los Mâ”œÃ­rtires, a la izquierda, y el antiguo nâ”¬â•‘ 49 del Coso. En el centro, luminoso y moderno, el nâ”¬â•‘ 43-45, en cuyos bajos se habâ”œÂ¡a reubicado hacâ”œÂ¡a bien poco la farmacia Râ”œÂ¡os. Sobre los tejados, despuntan levemente los remates de las torres de la iglesia parroquial de San Gil, y de la metropolitana de la Seo. Por el espacio de la plaza, dominada por la fuente de la Princesa, o Neptuno (fuera de plano, a la izquierda) circulan tranvâ”œÂ¡as pre-elâ”œÂ®ctricos, en tiempos en que este era el nudo gordiano de todos los ramales abiertos (Arrabal, Circunvalaciâ”œâ”‚n, Bajo Aragâ”œâ”‚n, Torrero, y Madrid).', 1896, 1896, 1896, 'Siglo XIX', 'CENTRO', 41.65200200, -0.88073900, '0101000020E6100000CFF9298E032FECBF9B7631CD74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28433958415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28433958415.webp', 'https://www.flickr.com/photos/zaragozaantigua/28433958415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25915, 'Pl. de Espaâ”œâ–’a 1970', 'Imagen de la unidad motora que tiraba de la composiciâ”œâ”‚n M+R 56 en la lâ”œÂ¡nea 5 "Venecia-Delicias", en direcciâ”œâ”‚n hacia la plaza de Rocasolano. Es abril y la primavera invita a recostar el codo en la ventanilla abierta, y mirar, y pensar, o sencillamente dejarse llevar por la sencilla contemplaciâ”œâ”‚n de lo contingente, como el fotâ”œâ”‚grafo que realiza esta captura. Al fondo, la referencial esquina de la plaza de Espaâ”œâ–’a donde intiman una entidad bancaria, y la DPZ Fuente visual: Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29549591093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29549591093.webp', 'https://www.flickr.com/photos/zaragozaantigua/29549591093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25924, 'Plaza de la Constituciâ”œâ”‚n 1903', 'Despejada imagen de la plaza de la Constituciâ”œâ”‚n capturada en el lapso de tiempo tras el desmontaje de la afrancesada fuente de Neptuno, y la inauguraciâ”œâ”‚n del Monumento a los Mâ”œÃ­rtires de la Religiâ”œâ”‚n y de la Patria, que aparece sâ”œâ”‚lo con el pedestal. En este trâ”œÃ­nsito, la plaza fue reurbanizada, eliminando el arbolado previo. De telâ”œâ”‚n de fondo, a la izquierda, el edificio de la Diputaciâ”œâ”‚n Provincial. En el entorno de la plaza circulan elâ”œÂ®ctricas unidades de la serie "Primitivos", en servicio en la lâ”œÂ¡nea Circunvalaciâ”œâ”‚n, y posiblemente Bajo Aragâ”œâ”‚n-Madrid. Fuente visual: cromolitografâ”œÂ¡a nâ”¬â•‘ 16 "Plaza de San Francisco", editada por Agustâ”œÂ¡n Alluâ”œÂ® en la serie "Zaragoza", en www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65206100, -0.88104300, '0101000020E6100000D0D4EB168131ECBFA0FF1EBC76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33894626923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33894626923.webp', 'https://www.flickr.com/photos/zaragozaantigua/33894626923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25934, 'Pl. de la Constituciâ”œâ”‚n c.1895', 'Inâ”œÂ®dita y luminosa imagen de la plaza de la Constituciâ”œâ”‚n capturada a nivel de la terrosa calzada en el arranque del tramo medio del Coso, con una interesante panorâ”œÃ­mica de la fachada oeste de la plaza, conformada de derecha a izquierda por los inmuebles del nâ”¬â•‘ 1, esquinero con el Coso Alto, el nâ”¬â•‘ 2 de la decimonâ”œâ”‚nica Diputaciâ”œâ”‚n Provincial de Zaragoza, y el esquinero nâ”¬â•‘ 3 con el principio de la calle de la Independencia, en cuyos bajos estaba el Cafâ”œÂ® Suizo. La solanera se puede mitigar, en el centro de la plaza, con la isleta de humedad proporcionada por la Fuente de la Princesa y la umbrâ”œÂ¡a del cerco de â”œÃ­rboles que la rodeaba, por donde asoma el bulto redondo de Neptuno, al que la calor que pueda llegar a hacer le importa bien poco. A la derecha, una "Jardinera" posiblemente del "tipo G", avanza arrastrada por caballerâ”œÂ¡as en servicio tal vez en la tranviaria lâ”œÂ¡nea del Bajo Aragâ”œâ”‚n, encaminada hacia la carretera de Castellâ”œâ”‚n. En primer tâ”œÂ®rmino, un seâ”œâ–’or cruza con resoluciâ”œâ”‚n el Coso, cubierto con tremendo sombrero, hacia la calle de Don Jaime I.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65208800, -0.88048300, '0101000020E610000011E335AFEA2CECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48024305998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48024305998.webp', 'https://www.flickr.com/photos/zaragozaantigua/48024305998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25997, 'Pl. de la Constituciâ”œâ”‚n 1925', 'Foto: Lucien Roisin. Vista desde el edificio La Joyita de la plaza de la Constituciâ”œâ”‚n 1 de buena parte del este de Zaragoza. En la plaza, a la derecha, el Gran Hotel de Europa. Un tranvâ”œÂ¡a de la serie 40 arrastra un remolque jardinera. Al fondo a la izquierda, el seminario de San Carlos. En el centro, el tramo del Coso Medio al completo. A la derecha, la torre de la iglesia de San Miguel y la de la central elâ”œÂ®ctrica de la Compaâ”œâ–’â”œÂ¡a Aragonesa, en la calle San Miguel, entre Porcell y Blancas. Fuente visual: www.facebook.com/photo.php?fbid=1630323313854055&set=...', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65209500, -0.88052700, '0101000020E6100000F9D687F5462DECBF4C7155D977D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21440773062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21440773062.webp', 'https://www.flickr.com/photos/zaragozaantigua/21440773062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26046, 'Pl. de la Constituciâ”œâ”‚n 1926', 'Vista de la plaza de la Constituciâ”œâ”‚n, "por fin pavimentada", en 1926. A la derecha, el Coso. A la izquierda, el paseo de la Independencia.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65214500, -0.88092700, '0101000020E6100000823AE5D18D30ECBFFD9FC37C79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31625382271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31625382271.webp', 'https://www.flickr.com/photos/zaragozaantigua/31625382271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21167, 'Puente de Santa Engracia 1893', 'Vista de la antigua Facultad de Medicina y Ciencias, con el puente de Santa Engracia sobre el Huerva en primer plano, ubicado en la actual confluencia del paseo de la Constituciâ”œâ”‚n con la plaza de Basilio Paraâ”œÂ¡so. Fuente visual: <a href=&quot;', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23828738014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23828738014.webp', 'https://www.flickr.com/photos/zaragozaantigua/23828738014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21179, 'Puente de Santa Engracia c.1890', 'Imagen capturada durante las obras de construcciâ”œâ”‚n del nuevo edificio para las Facultades de Medicina y Ciencias de la Universidad de Zaragoza, levantado sobre el campo de Lezcano con proyecto del arquitecto Ricardo Magdalena. En primer tâ”œÂ®rmino, el puente de Santa Engracia sobre el râ”œÂ¡o Huerva, que hacia la izquierda daba acceso a los paseos de Sagasta y de las Damas, y sobre el que desde 1886 transitaban los tranvâ”œÂ¡as de la lâ”œÂ¡nea de Torrero. Tras el edificio de las dos Facultades, se construirâ”œÂ¡a el Hospital Clâ”œÂ¡nico, y mâ”œÃ­s allâ”œÃ­, el Departamento Anatâ”œâ”‚mico. El conjunto fue inaugurado oficialmente el 18 de octubre de 1893. Este puente fue construido en 1885, quedando soterrado en 1923 con el cubrimiento de ese tramo del râ”œÂ¡o Huerva.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64708500, -0.88555800, '0101000020E6100000E3C116BB7D56ECBFB75D68AED3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33546560358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33546560358.webp', 'https://www.flickr.com/photos/zaragozaantigua/33546560358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21190, 'Plaza de Aragâ”œâ”‚n 1893', 'Inâ”œÂ®dita imagen capturada desde la altura del hotelito del nâ”¬â•‘ 10 de la plaza de Aragâ”œâ”‚n y centrada en la luminosa fachada de la nueva sede de la Capitanâ”œÂ¡a General, cuyo proyecto fue realizado bajo la supervisiâ”œâ”‚n de los ingenieros militares Carlos Vila y Lara, Francisco Rizzo, Honorato de Saleta y Josâ”œÂ® Gâ”œâ”‚mez Pallete. Su alabeada fachada se adecua a la planta de los solares 2, 3 y 4 de la Manzana E adquiridos por el Ramo de la Guerra tras la urbanizaciâ”œâ”‚n de los terrenos donde tuvo lugar la Exposiciâ”œâ”‚n aragonesa de 1868. A la derecha, vista parcial del vecino hotelito del nâ”¬â•‘ 10 de la plaza, ya remodelado de su traza original segâ”œâ•‘n proyecto del arquitecto Fernando de Yarza Fernâ”œÃ­ndez-Treviâ”œâ–’o. El solar de este inmueble, y sobre el plano del proyecto de la Capitanâ”œÂ¡a, se intentâ”œâ”‚ que tambiâ”œÂ®n fuera adquirido para formar parte del recinto militar, pero no fructificaron las gestiones. A la izquierda, vista del arbolado paseo de la Lealtad y el desemboque en â”œÂ®l del camino de los Cubos, con la esquinera zona inmediata a la Capitanâ”œÂ¡a todavâ”œÂ¡a en obras de urbanizaciâ”œâ”‚n', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64807900, -0.88567600, '0101000020E61000005F44DB317557ECBFB91CAF40F4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50089723907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50089723907.webp', 'https://www.flickr.com/photos/zaragozaantigua/50089723907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21199, 'Puente de Santa Engracia c.1894', 'Imagen capturada en el momento en que una calesa cubierta cruza el puente de Santa Engracia sobre el râ”œÂ¡o Huerva, posiblemente encaminada hacia la puerta de Santa Engracia y la plaza de Aragâ”œâ”‚n. Al fondo, el nuevo edificio construido para la enseâ”œâ–’anza de las Facultades de Medicina y Ciencias, actual Paraninfo de la Universidad de Zaragoza. Sobre el barrizal la calesa circula por el trazado por el que desde septiembre de 1886 transitaba el tranvâ”œÂ¡a de la lâ”œÂ¡nea de Torrero.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.64686100, -0.88561100, '0101000020E6100000994A3FE1EC56ECBF68075C57CCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53152875909.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53152875909.webp', 'https://www.flickr.com/photos/zaragozaantigua/53152875909/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21274, 'Puerta de Santa Engracia 1903', 'Imagen de la puerta de Santa Engracia. Tras las rejas, y a la izquierda, el edificio de Capitanâ”œÂ¡a en la arbolada glorieta de Pignatelli. Al fondo, el final de la calle de la Independencia. La postal fue editada por el establecimiento "La Reina de las Tintas" en 1903, dentro de una serie titulada "Zaragoza". El ejemplar de la imagen fue circulado en mayo de 1904, cuatro meses antes del derribo de la â”œâ•‘ltima versiâ”œâ”‚n de esta puerta. Fuente: www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22820925978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22820925978.webp', 'https://www.flickr.com/photos/zaragozaantigua/22820925978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21278, 'Glorieta de Pignatelli c.1900', 'Imagen de la Glorieta de Pignatelli, identificada ya como "Plaza de Aragâ”œâ”‚n", antes de su remodelaciâ”œâ”‚n e instalaciâ”œâ”‚n en su centro del Monumento al Justicia, en 1904. En primer tâ”œÂ®rmino, a la derecha, estatua de Ramâ”œâ”‚n de Pignatelli. Al fondo, Facultad de Medicina, Capitanâ”œÂ¡a y Puerta de Santa Engracia. Fuente: www.delcampe.net', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64782300, -0.88521400, '0101000020E610000054C37E4FAC53ECBF5E4C33DDEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24456990035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24456990035.webp', 'https://www.flickr.com/photos/zaragozaantigua/24456990035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21305, 'Puerta de Santa Engracia c.1903', 'Imagen de la puerta de Santa Engracia centrada en el ingreso principal a la plaza de Aragâ”œâ”‚n, jalonado por las casetas de cobro de Consumos. El tendido tranviario de la lâ”œÂ¡nea de Torrero circulaba a izquierda y derecha de la imagen, como sucedâ”œÂ¡a desde la inauguraciâ”œâ”‚n de la lâ”œÂ¡nea en 1886, por lo que parece que tuvo poca responsabilidad en el derribo de esta â”œâ•‘ltima versiâ”œâ”‚n de la histâ”œâ”‚rica puerta de Santa Engracia, realizado un aâ”œâ–’o despuâ”œÂ®s. Fuente visual: Colecciâ”œâ”‚n Montserrat/Sociedad Estereoscâ”œâ”‚pica Espaâ”œâ–’ola (Barcelona), en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œÂ¡a profesional y comercial 1850-1970, PUZ.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34834825882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34834825882.webp', 'https://www.flickr.com/photos/zaragozaantigua/34834825882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21469, 'Colegio del Salvador c.1910', 'Fachada principal del colegio del Salvador. Al fondo, edificio de la Capitanâ”œÂ¡a General en la plaza de Aragâ”œâ”‚n.', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53478001422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53478001422.webp', 'https://www.flickr.com/photos/zaragozaantigua/53478001422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23393, 'Puente de La Muela 1796', 'Dibujo representando la planta y perfil del puente construido sobre el Canal Imperial para dar paso al camino de la Muela, tambiâ”œÂ®n denominado camino Real de las Postas para Madrid. Labrado en piedra de sillerâ”œÂ¡a, ademâ”œÃ­s de mejorar considerablemente el trâ”œÃ­nsito caminero hacia la Villa y Corte, por â”œÂ®l tambiâ”œÂ®n pasaba la acequia de Santa Bâ”œÃ­rbara. Fuente visual: Dibujo de Fâ”œÂ®lix Guitarte, grabado por Manuel Navarro, e impreso en Zaragoza por Francisco Magallâ”œâ”‚n (1796) dentro de la "Descripciâ”œâ”‚n de los canales Imperial de Aragâ”œâ”‚n i Real de Tauste dedicada a los augustos soberanos D. Carlos IV i D. Marâ”œÂ¡a Luisa de Borbâ”œâ”‚n por el actual protector por S. Magestad de ambos canales el conde de Sâ”œÃ­stago".', 1796, 1796, 1796, 'Siglo XIX', NULL, 41.64029600, -0.95480000, '0101000020E6100000CB10C7BAB88DEEBF3BE12538F5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45628886361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45628886361.webp', 'https://www.flickr.com/photos/zaragozaantigua/45628886361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21633, 'Plaza de Aragâ”œâ”‚n 1923', 'Luminosa imagen capturada en la plaza de Aragâ”œâ”‚n durante el râ”œÃ­pido paso por la ciudad, a comienzos de diciembre de ese aâ”œâ–’o, del rey Alfonso XIII de Borbâ”œâ”‚n y la reina Victoria Eugenia de Battenberg, en su regreso del viaje oficial al reino de Italia, donde se reunieron con el rey Victor Manuel III, el papa Pâ”œÂ¡o XI, y el presidente del Consejo de ministros, Benito Mussolini. Si bien este viaje institucional habâ”œÂ¡a sido organizado durante los â”œâ•‘ltimos coletazos de la Monarquâ”œÂ¡a constitucional, se convirtiâ”œâ”‚ en un acto polâ”œÂ¡tico para normalizar y legitimar el golpe de Estado del general Primo de Rivera (que les acompaâ”œâ–’â”œâ”‚ en el viaje) realizado unas semanas antes, y la Dictadura reciâ”œÂ®n instaurada. Ademâ”œÃ­s, escenificâ”œâ”‚ la buena sintonâ”œÂ¡a de estos dos regâ”œÂ¡menes dictatoriales en la convulsa Europa de comienzos de los aâ”œâ–’os 20. En la imagen, la Real pareja acompaâ”œâ–’ada por el alcalde Juan Fabiani en el coche que les transportaba por la ciudad durante su estancia, junto a las verjas de la Capitanâ”œÂ¡a General, donde se hospedaron. Al fondo, algunos de los hotelitos del lado oeste de la plaza de Aragâ”œâ”‚n. En primer tâ”œÂ®rmino, el nâ”¬â•‘ 10, durante las obras de recrecimiento y remodelaciâ”œâ”‚n acometidas para darle un extra en altura de dos plantas, mâ”œÃ­s â”œÃ­tico. A continuaciâ”œâ”‚n y tras la calle de Canfranc, el inmueble del nâ”¬â•‘ 11.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64805500, -0.88546100, '0101000020E610000046459C4EB255ECBF30815B77F3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48502848826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48502848826.webp', 'https://www.flickr.com/photos/zaragozaantigua/48502848826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23066, 'Puente del ferrocarril 1997', '"Puente del ferrocarril", â”œâ”‚leo sobre lienzo, Ignacio Mayayo, 1997. Vista del puente del ferrocarril que cruzaba el râ”œÂ¡o Ebro (a la derecha, fuera de plano) entre 1968 y 2007. Estâ”œÃ­ tomada desde el actual camino de La Alfranca, que lleva hasta allâ”œÂ¡ pasando por La Cartuja Baja. Al fondo, bloques de viviendas en la calle de Fray Luis Urbano del barrio de Las Fuentes. Este puente se mantuvo en pie provisionalmente entre el de Manuel Gimâ”œÂ®nez Abad y el actual puente del AVE.', 1997, 1997, 1997, 'Anos 90', 'LAS FUENTES', 41.65078900, -0.85334500, '0101000020E61000005890662C9A4EEBBF5CCCCF0D4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52471595717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52471595717.webp', 'https://www.flickr.com/photos/zaragozaantigua/52471595717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21900, 'Pâ”¬â•‘. de Marina Moreno 1939', 'Imagen capturada en el arranque del paseo de Marina Moreno (hasta poco antes, avenida de Galâ”œÃ­n y Garcâ”œÂ¡a Hernâ”œÃ­ndez) durante el ceremonial de homenaje a la XV bandera de la Legiâ”œâ”‚n (entre 1936-37 Bandera o Tercio General Sanjurjo), mediante la imposiciâ”œâ”‚n de la corbata de San Fernando por el general â”œÃ¼lvaro Sueiro y Vilariâ”œâ–’o, con presencia en la tribuna de autoridades del presidente de la DPZ Miguel Alluâ”œÂ® Salvador y el alcalde Juan Josâ”œÂ® Rivas Bosch. De telâ”œâ”‚n de fondo edilicio, traseras de los "hotelitos" nâ”¬â•‘ 7 y 6 de la plaza de Aragâ”œâ”‚n, bajo los que esperan su turno para recibir diversas medallas militares concedidas por mâ”œÂ®ritos adquiridos durante la "Cruzada" de 1936-39 (esta ceremonia se realizâ”œâ”‚ en octubre de este â”œâ•‘ltimo aâ”œâ–’o). Entre ellos destaca el coronel Santiago Amado Lâ”œâ”‚riga, que en 1943 serâ”œÂ¡a segundo jefe de la Divisiâ”œâ”‚n Azul durante su participaciâ”œâ”‚n en la "Cruzada contra el Bolchevismo".', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64751800, -0.88478500, '0101000020E610000039B9DFA12850ECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51410344109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51410344109.webp', 'https://www.flickr.com/photos/zaragozaantigua/51410344109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21970, 'Plaza de Aragâ”œâ”‚n 1946', 'Imagen de la temporal composiciâ”œâ”‚n tranviaria de extraordinaria capacidad formada por las novâ”œÂ¡simas unidades nâ”¬â•‘ 202 (haciendo de "motor") y nâ”¬â•‘ 203 (en funciones de "remolque") de la serie "200", habilitadas para la Lâ”œÂ¡nea 11. Parque, circulando en direcciâ”œâ”‚n a la plaza del Emperador Carlos V. De fondo, el provinciano panorama edilicio de la antigua plaza de Aragâ”œâ”‚n. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64802900, -0.88528100, '0101000020E610000048A5D8D13854ECBF07EE409DF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23600301759.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23600301759.webp', 'https://www.flickr.com/photos/zaragozaantigua/23600301759/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22074, 'Pl. de Basilio Paraâ”œÂ¡so 1951', 'Imagen capturada desde cierta altura en el Edificio Elâ”œÂ¡seos con vista, en primer tâ”œÂ®rmino de la reciâ”œÂ®n reformada plaza de Basilio Paraâ”œÂ¡so, con sus imponentes columnas-farolas de hormigâ”œâ”‚n armado. La ovalada isleta central ya habâ”œÂ¡a sido despojada previamente (octubre de 1950) de la estatua de Câ”œÂ®sar Augusto, y tendrâ”œÂ¡a que esperar unos aâ”œâ–’os hasta la instalaciâ”œâ”‚n de una llamativa fuente. Dos trolebuses de la nueva lâ”œÂ¡nea del Terminillo (estrenada en mayo) uno por direcciâ”œâ”‚n de terminal (Duquesa Villahermosa y paseo de la Independencia), coinciden en la plaza. Fuente visual: Zaragoza 1908-2008. FCC.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64723600, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF9D6516A1D8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524929189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524929189.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524929189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
