INSERT INTO public.photos VALUES (22197, 'Pl. de Basilio Paraâ”œÂ¡so 1958', 'Imagen de la plaza de Paraâ”œÂ¡so y la Facultad de Medicina, uno de los espacios recurrentes de la ciudad editados luego como postal. Circula una composiciâ”œâ”‚n tranviaria de la lâ”œÂ¡nea 5 "Torrero-Delicias" (posiblemente, un motor de la serie 60, tirando de un remolque de la 70) en direcciâ”œâ”‚n sur. Fuente visual: Ediciones DARVI, en www.abebooks.com', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64730700, -0.88579600, '0101000020E610000008AF5DDA7058ECBF66BCADF4DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33333814704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33333814704.webp', 'https://www.flickr.com/photos/zaragozaantigua/33333814704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22212, 'Pl. de Basilio Paraâ”œÂ¡so 1958', 'Fotografâ”œÂ¡a tomada desde la altura del Edificio Elâ”œÂ¡seos y centrada en la plaza de Basilio Paraâ”œÂ¡so tras la remodelaciâ”œâ”‚n culminada con una fuente caracterizada por sus juegos de agua, a distintas alturas, y en colores. Tres aâ”œâ–’os mâ”œÃ­s tarde esta fuente fue ampliada con mâ”œÃ­s chorros y luminarias, para embellecer aâ”œâ•‘n mâ”œÃ­s lo que ya era un primor. Alrededor circulan un par de trolebuses de la lâ”œÂ¡nea Terminillo, los dos de regreso a la terminal de la plaza de Santa Engracia, un tranvâ”œÂ¡a de la lâ”œÂ¡nea 11. Parque, hacia el original Parque de Buenavista, y un tranvâ”œÂ¡a de la lâ”œÂ¡nea 15. Casablanca, hacia la terminal de la plaza de Espaâ”œâ–’a. La panorâ”œÃ­mica de la plaza de Aragâ”œâ”‚n ofrece una buena vista de los hotelitos a ambos lados de su ovalada y arbolada traza. Este escenario serâ”œÃ­ radicalmente modificado pocos aâ”œâ–’os despuâ”œÂ®s, cuando las obras de remodelaciâ”œâ”‚n del eje de comunicaciâ”œâ”‚n entre la plaza de Espaâ”œâ–’a y la plaza de Aragâ”œâ”‚n. Fuente visual: www.delcampe.net', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45981521284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45981521284.webp', 'https://www.flickr.com/photos/zaragozaantigua/45981521284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22216, 'Pl. de Basilio Paraâ”œÂ¡so 1954', 'Imagen capturada desde la relativa altura del antiguo y desaparecido inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, esquinero con la calle del Doctor Cerrada, y centrada en el entorno de la plaza de Paraâ”œÂ¡so y su engarce con la plaza de Aragâ”œâ”‚n, de la que destacan los hotelitos construidos desde la calle de Agustina Simâ”œâ”‚n, antigua de Puigcerdâ”œÃ­. A la izquierda, el chaflâ”œÃ­n del edificio de la Capitanâ”œÂ¡a General. Al fondo, la moderna manzana recayente entre el paseo de Marina Moreno y la calle del Arquitecto Yarza, y el esquinero edificio del arranque de la calle de Madre Vedruna. A la derecha se destaca la mole del colegio del Salvador. Por la plaza de Paraâ”œÂ¡so transita un trolebâ”œâ•‘s BUT de un piso en servicio en la lâ”œÂ¡nea Terminillo, de regreso de la Ciudad Jardâ”œÂ¡n; y un tranvâ”œÂ¡a de la serie 200 en servicio en la lâ”œÂ¡nea 11.Parque encaminada hacia la terminal de la plaza de Espaâ”œâ–’a. Fuente visual: AMZ', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46878111802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46878111802.webp', 'https://www.flickr.com/photos/zaragozaantigua/46878111802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22221, 'Plaza de Paraâ”œÂ¡so c.1957', 'Interesante imagen capturada en la plaza de Basilio Paraâ”œÂ¡so y centrada en el referencial Edificio Elâ”œÂ¡seos, especialmente tras la aparatosa instalaciâ”œâ”‚n en su parte superior de la tremenda peineta publicitaria de una entidad de ahorro local. Hacia la izquierda arranca en ascenso el paseo del General Mola, por donde se encamina una composiciâ”œâ”‚n tranviaria de la serie 100, en servicio en la lâ”œÂ¡nea 5. Venecia-Delicias. En la plaza destaca el aâ”œÂ®reo tendido tranviario y trolebusero, tal que una elâ”œÂ®ctrica tela de araâ”œâ–’a; la acuâ”œÃ­tica fuente y el puesto a cubierto del guardia urbano encargado de regular el trâ”œÃ­nsito viario, que no es mucho. Hacia la derecha, arranque del paseo de Calvo Sotelo y vista parcial de la Facultad de Medicina y Ciencias de la Universidad.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64718900, -0.88549300, '0101000020E61000001DC87A6AF555ECBF5CAAD216D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48330009202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48330009202.webp', 'https://www.flickr.com/photos/zaragozaantigua/48330009202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22223, 'Plaza de Aragâ”œâ”‚n 1958', 'Imagen capturada en original blanco y negro en la plaza de Aragâ”œâ”‚n, y coloreada posteriormente a mano para ser editada como postal. La antropolâ”œâ”‚gica escena recoge el dominguero paseo arriba, paseo abajo, por el antiguo bulevar de Independencia, al fondo, y su continuidad por la arbolada glorieta o plaza de Aragâ”œâ”‚n, echando la tarde en una actividad sana y muy poco economicista, para horror del sector terciario. Centra la imagen el Monumento al Justiciazgo. Detrâ”œÃ­s, el cenotafio "A los funcionarios muertos en agosto de 1920".', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64806300, -0.88492500, '0101000020E6100000A835CD3B4E51ECBFB35F77BAF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48953051398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48953051398.webp', 'https://www.flickr.com/photos/zaragozaantigua/48953051398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
