INSERT INTO public.photos VALUES (22404, 'Plaza de Paraâ”œÂ¡so 1969', 'Imagen en altura de la antigua plaza de Paraâ”œÂ¡so, con un amplio catâ”œÃ­logo de elementos de un pasado que pasâ”œâ”‚, salvo en muy contadas y excepcionales singularidades. El resto, sean componentes edilicios, estâ”œÃ­ticos, semovientes, sombras, vegetaciâ”œâ”‚n, ornamento, fluidos varios, son muy otros. Aunque, en el fondo, la suma de todos sus elementos energâ”œÂ®ticos esenciales siga siendo la misma. Fuente: Gerardo Sancho Ramo, en AMZ.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23943835502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23943835502.webp', 'https://www.flickr.com/photos/zaragozaantigua/23943835502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
