INSERT INTO public.photos VALUES (22534, 'Plaza Paraâ”œÂ¡so 1975', '1975. Aâ”œÂ®rea vista del entorno de la Plaza de Paraâ”œÂ¡so, Plaza de Aragâ”œâ”‚n, Paseo Independencia, Paseo Pamplona, y Marina Moreno. Al fondo, la Avenida de los Pirineos, con la ACTUR como gran actuaciâ”œâ”‚n urbanâ”œÂ¡stica de urgencia que, lo que se dice urgencia, ya no lo era mucho. En la Plaza de Salamero, a la izquierda, impone la visiâ”œâ”‚n del edificio reciâ”œÂ®n nacido, obra de Lorenzo Monclâ”œâ•‘s Ramâ”œÂ¡rez, con 55,34 metros de altura, y 16 plantas. Todo un impacto. En la Plaza de Aragâ”œâ”‚n, siguen cayendo hotelitos, en beneficios de otros edificios de mâ”œÃ­s alturas y beneficios. La justificaciâ”œâ”‚n es que, ya puestos, se trataba de igualar visualmente los edificios de toda la Plaza, para atraer turistas e inversiones. El solar del antiguo Colegio de los PP Jesuitas, abajo, ejerce como transitorio vivero de herbâ”œÃ­ceas silvestres, mientras culminan las operaciones urbanâ”œÂ¡sticas de intercambio de cromos que, ad maiorem dei gloriam, colocarâ”œÃ­n aquâ”œÂ¡ en breve la nueva sede central de una importante entidad de ahorro.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64718800, -0.88572000, '0101000020E610000047382D78D157ECBF8C2E6F0ED7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14793197140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14793197140.webp', 'https://www.flickr.com/photos/zaragozaantigua/14793197140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22589, 'Edificio central Ibercaja 1977', 'Imagen de las vallas metâ”œÃ­licas que delimitaban el perâ”œÂ¡metro de obra de construcciâ”œâ”‚n del edificio central de la Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”œâ”‚n y Rioja en la plaza de Paraâ”œÂ¡so, segâ”œâ•‘n proyecto de Teodoro Râ”œÂ¡os Usâ”œâ”‚n. En este solar se ubicaban anteriormente el veterano colegio y la joven iglesia de los Jesuitas. La captura, desde el Paseo del General Mola, permite una visual irrepetible de los bloques de viviendas de San Ignacio de Loyola, tramo Pedro Marâ”œÂ¡a Ric-Francisco de Vitoria. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64661700, -0.88490000, '0101000020E6100000705F07CE1951ECBFD1048A58C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15751683372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15751683372.webp', 'https://www.flickr.com/photos/zaragozaantigua/15751683372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
