INSERT INTO public.photos VALUES (22734, 'Calvo Sotelo 1973', 'Imagen de una unidad tranviaria de la serie 200 (posiblemente, el nâ”¬â•‘ 212), en servicio en la lâ”œÂ¡nea 11 "Parque-San Josâ”œÂ®", saliendo del paseo de Calvo Sotelo, al fondo, y entrando en el espacio de la plaza de Basilio Paraâ”œÂ¡so, hacia la terminal en San Josâ”œÂ®. A la derecha, el edificio de la Facultad de Medicina y Ciencias. Fuente visual: Foto Heidiland, a travâ”œÂ®s de www.forotrenes.com/', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64681000, -0.88568800, '0101000020E610000070B54E5C8E57ECBFE65C8AABCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31172688815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31172688815.webp', 'https://www.flickr.com/photos/zaragozaantigua/31172688815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22740, 'Plaza Paraâ”œÂ¡so 1972', 'Un tranvâ”œÂ¡a de la lâ”œÂ¡nea 11 "Parque-San Josâ”œÂ®" se dirige hacia el parque Primo de Rivera, a su paso por la plaza de Basilio Paraâ”œÂ¡so, en octubre, durante la 32â”¬Â¬ Ferial Oficial y Nacional de Muestras. Al fondo, un trolebâ”œâ•‘s encaminado hacia la Ciudad Jardâ”œÂ¡n, el edificio de Capitanâ”œÂ¡a, y el nuevo bloque de plaza de Aragâ”œâ”‚n nâ”¬â•‘ 11 en construcciâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=1577623582253481&set=...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64727400, -0.88587100, '0101000020E6100000B131AF230E59ECBF8BC6DADFD9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31624782131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31624782131.webp', 'https://www.flickr.com/photos/zaragozaantigua/31624782131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22776, 'Plaza de Paraâ”œÂ¡so 1976', 'Maqueta del moderno edificio proyectado como sede central de la Caja de Ahorros de Zaragoza, Aragâ”œâ”‚n y Rioja, a construir en la plaza de Paraâ”œÂ¡so. Ello suponâ”œÂ¡a el traslado desde la sede construida sobre el solar de la antigua casa de Zaporta hasta los terrenos del colegio del Salvador adquiridos a los PP. Jesuitas. Su realizaciâ”œâ”‚n, con licencia como edificio de caracterâ”œÂ¡sticas singulares, y proyecto de Teodoro Râ”œÂ¡os Usâ”œâ”‚n, tuvo un coste econâ”œâ”‚mico de varios miles de millones de pesetas. El resultado, un referente sâ”œÂ¡mbolo visual a la altura de uno de los poderes polâ”œÂ¡ticos y econâ”œâ”‚micos mâ”œÃ­s influyentes de la regiâ”œâ”‚n aragonesa. Entre el trâ”œÃ­fico ya no figuran unidades del tranvâ”œÂ¡a de la ciudad, pues la â”œâ•‘ltima lâ”œÂ¡nea Parque- San Josâ”œÂ® habâ”œÂ¡a sido clausurada pocos meses antes. Fuente visual: revista "Aragâ”œâ”‚n turâ”œÂ¡stico y monumental", SIPA.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34455945110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34455945110.webp', 'https://www.flickr.com/photos/zaragozaantigua/34455945110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22778, 'Iglesia de la Madre del Salvador 1970', 'Comienza la demoliciâ”œâ”‚n de la iglesia del Colegio del Salvador de los jesuitas (detrâ”œÃ­s, a la izquierda). Habâ”œÂ¡a sido levantada en 1960. Abajo, el inicio del paseo de las Damas. La instantâ”œÃ­nea, tomada desde el paseo del General Mola. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64646500, -0.88523600, '0101000020E610000049BDA772DA53ECBF1B81785DBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36172340170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36172340170.webp', 'https://www.flickr.com/photos/zaragozaantigua/36172340170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22795, 'Plaza Paraâ”œÂ¡so 1978', 'La plaza de Basilio Paraâ”œÂ¡so desde la altura del Edificio Elâ”œÂ¡seos. En primer plano, figuras del Monumento al Ahorro, conjunto escultâ”œâ”‚rico encargado por la Caja de Ahorros de Zaragoza a Fâ”œÂ®lix Burriel en 1945. Un cartel de esa entidad anuncia las obras de su nueva sede, a la derecha. Abajo, obras para colocar en la ajardinada rotonda central la estatua de Câ”œÂ®sar Augusto, que regresa de su periplo por las murallas romanas junto al Torreâ”œâ”‚n de la Zuda.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44124329622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44124329622.webp', 'https://www.flickr.com/photos/zaragozaantigua/44124329622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23428, 'Santa Fe 1999', 'Iglesia del monasterio de Santa Marâ”œÂ¡a de Santa Fe, vista desde la entrada a su recinto amurallado, a orillas del râ”œÂ¡o Huerva y entre Cuarte y Cadrete. Este monasterio cisterciense se enclavâ”œâ”‚ aquâ”œÂ¡ en 1341, y la iglesia barroca, que se encuentra en ruinas, fue construida en 1774. Pese a la distancia de 8 km entre ellos, el lugar de Santa Fe forma parte del distrito de Casablanca, que hasta mayo de 2003 aâ”œâ•‘n era oficialmente un barrio rural.', 1999, 1999, 1999, 'Anos 90', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50198851173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50198851173.webp', 'https://www.flickr.com/photos/zaragozaantigua/50198851173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23016, 'P.â”¬â•‘ de la Constituciâ”œâ”‚n 1994', 'Vista del paseo de la Constituciâ”œâ”‚n, en su arranque desde la plaza de Paraâ”œÂ¡so, en octubre de 1994. En el jardâ”œÂ¡n estâ”œÃ­n plantadas unas tiendas de campaâ”œâ–’a correspondientes a la acampada reivindicativa de la Plataforma 0,7, dentro de un movimiento a nivel nacional. Se reclamaba el cumplimiento de un compromiso adquirido 20 aâ”œâ–’os antes en la ONU por el cual los paâ”œÂ¡ses ricos debâ”œÂ¡an dedicar el 0''7 del Producto Interior Bruto a programas de ayuda al desarrollo en los paâ”œÂ¡ses pobres. Esta acampada se prolongâ”œâ”‚ durante un mes, siendo hostigada por ultraderechistas. Fuente: www.zaragozarebelde.org', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64723400, -0.88519300, '0101000020E610000077BD34458053ECBFFC6D4F90D8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37778586271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37778586271.webp', 'https://www.flickr.com/photos/zaragozaantigua/37778586271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23126, 'Plaza de Paraâ”œÂ¡so 2009', 'Imagen capturada en altura, posiblemente desde el chaflanero edificio "Elâ”œÂ¡seos", de la rotonda automovilâ”œÂ¡stica en que habâ”œÂ¡a sido convertida la plaza de Paraâ”œÂ¡so. Cuando a finales de los aâ”œâ–’os 80 este espacio fue remodelado cosmâ”œÂ®ticamente, tras una nueva reubicaciâ”œâ”‚n de la estatua de Câ”œÂ®sar Augusto, la rotonda fue desposeâ”œÂ¡da de su densa vegetaciâ”œâ”‚n, y en su lugar se colocâ”œâ”‚ una preciosa fuente que no estorbaba la visual, y que los dâ”œÂ¡as de recio viento norte era mejor dejar apagada. En 2011, las obras de la lâ”œÂ¡nea 1 del moderno tranvâ”œÂ¡a incluyeron necesariamente una intervenciâ”œâ”‚n en esta zona, dejâ”œÃ­ndola con su aspecto actual. Entonces, a las filas del gran eje opositor al tranvâ”œÂ¡a, se uniâ”œâ”‚ un grupo de presiâ”œâ”‚n especâ”œÂ¡fico que defendiâ”œâ”‚ esta fuente como valioso patrimonio artâ”œÂ¡stico, cultural, e histâ”œâ”‚rico de los aâ”œâ–’os 90 del siglo XX. Fuente visual: www.verpueblos.com/', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.64731900, -0.88586200, '0101000020E6100000E59CD843FB58ECBF2B8A5759DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31230842860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31230842860.webp', 'https://www.flickr.com/photos/zaragozaantigua/31230842860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23144, 'Lago de Paraâ”œÂ¡so 2006', 'Foto: Oliver Duch. Aspecto de la plaza de Basilio Paraâ”œÂ¡so inundada a causa del reventâ”œâ”‚n de una tuberâ”œÂ¡a de agua de 90 aâ”œâ–’os, el domingo 18 de junio de 2006. A la derecha, paseo de la Constituciâ”œâ”‚n, por donde el lâ”œÂ¡quido elemento siguiâ”œâ”‚ su curso natural sobre el Huerva, llegando hasta el paseo de la Mina. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.64713000, -0.88578500, '0101000020E61000000E32C9C85958ECBF5721E527D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31946040346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31946040346.webp', 'https://www.flickr.com/photos/zaragozaantigua/31946040346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23196, 'Cinema Elâ”œÂ¡seos 2015', 'El "Cinema Elâ”œÂ¡seos" formaba parte del gran proyecto que Teodoro Râ”œÂ¡os Balaguer diseâ”œâ–’â”œâ”‚ en 1939 para el nuevo "Edificio Elâ”œÂ¡seos", estratâ”œÂ®gico entre el arranque de la nueva avenida del General Mola, y el paseo de Calvo Sotelo, con su esquina achaflanada mirando hacia la plaza de Paraâ”œÂ¡so. Fue inaugurado como sala de proyecciâ”œâ”‚n comercial a finales de 1944, con capacidad para 500 espectadores, que visionaron "Me casâ”œÂ® con una bruja", de Renâ”œÂ® Clair. Allâ”œÂ¡ tuvo lugar, al aâ”œâ–’o siguiente, la primera sesiâ”œâ”‚n del "Cineclub de Zaragoza", y en 1967 se convirtiâ”œâ”‚ en la primera "Sala de Arte y Ensayo" de la ciudad. Entre 1987 y 1991, ejerciâ”œâ”‚ de sede de la Filmoteca de Zaragoza, cuando â”œÂ®sta andaba de romerâ”œÂ¡a por diversas ubicaciones de la ciudad. En 1993, fue rehabilitado y restaurado respetando el original estilo de sus orâ”œÂ¡genes, y su aforo quedâ”œâ”‚ en 396 localidades. Era una singular "rara avis" en el panorama de las salas de proyecciâ”œâ”‚n de la ciudad, cuando estallâ”œâ”‚ la plaga de los "complejos multisalas". En 2009 fue declarado "Bien Catalogado del Patrimonio Cultural Aragonâ”œÂ®s". A comienzos del mes de agosto de 2014, cuando se acercaba su aniversario 70 como sala de cine, y tras la proyecciâ”œâ”‚n del filme "Marsella", de Belâ”œÂ®n Macâ”œÂ¡as, se anunciâ”œâ”‚ su cierre temporal para "modernizar el sistema de proyecciâ”œâ”‚n", lo que significaba sustituir el tradicional de celuloide, por el sistema digital, y acondicionar en consecuencia la sala. Pasaron los meses, sin que ninguna actividad indicara que se estaba llevando a cabo la anunciada "digitalizaciâ”œâ”‚n". Transcurridos 14 meses, el Ayuntamiento seguâ”œÂ¡a sin haber recibido ninguna solicitud de licencia de obras para tal fin. La empresa propietaria del local no soltaba prenda, y mantenâ”œÂ¡a sus declaraciones realizadas en agosto de 2014, en el sentido de "realizar un estudio sobre la mejor manera de proceder a la transformaciâ”œâ”‚n, enmarcada dentro de la apuesta de Zaragoza Urbana por el desarrollo de la actividad cultural de la ciudad". Mientras, los demâ”œÃ­s esperâ”œÃ­bamos,', 2015, 2015, 2015, 'Siglo XXI', 'CENTRO', 41.64627800, -0.88563200, '0101000020E6100000765089EB1857ECBFE90FCD3CB9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24473996940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24473996940.webp', 'https://www.flickr.com/photos/zaragozaantigua/24473996940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
