INSERT INTO public.photos VALUES (23668, 'Plaza de Aragâ”œâ”‚n 1920', 'Imagen centrada en la fachada del gran edificio de la Capitanâ”œÂ¡a General, construido sobre tres de los cuatro solares de la manzana suroccidental de la antigua glorieta de Pignatelli. A su derecha, el edificio construido sobre el cuarto solar, con diseâ”œâ–’o de Fernando de Yarza. Casualmente, transita en direcciâ”œâ”‚n al sur la elâ”œÂ®ctrica y diâ”œÃ­fana unidad 27 de la tranviaria lâ”œÂ¡nea "Torrero", una jardinera motora que poco despuâ”œÂ®s serâ”œÂ¡a reformada, cerrâ”œÃ­ndola, porque el clima zaragozano parece aconsejarlo, durante la mayor parte del aâ”œâ–’o. Fuente visual: www.ebay.es/', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31354016305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31354016305.webp', 'https://www.flickr.com/photos/zaragozaantigua/31354016305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
